parameters.jsCode:
// Normalize incoming payload from CTO Agent (Telegram-origin call)
// Expected upstream shape (from Execute Workflow call):
// { user_message: string, repo_owner: string, repo_name: string, branch: string, chat_id: string }

const input = $input.first().json;

if (!input.user_message || typeof input.user_message !== 'string' || input.user_message.trim().length < 5) {
  throw new Error(
    'user_message tidak valid (kosong/terlalu pendek, min 5 karakter). ' +
    'Kemungkinan penyebab: CTO_Agent gagal mengisi parameter via $fromAI() ' +
    'karena description tool ambigu atau system prompt kurang spesifik. ' +
    'Payload diterima: ' + JSON.stringify(input)
  );
}

return [{
  json: {
    user_message: input.user_message.trim(),
    repo_owner: input.repo_owner || '',
    repo_name: input.repo_name || '',
    branch: input.branch || '',
    chat_id: input.chat_id || '',
    received_at: new Date().toISOString()
  }
}];

// Parse Intent Parser's JSON output safely.
// Handles cases where model wraps output in markdown fences despite instructions.

const raw = $input.first().json.message?.content
  || $input.first().json.content
  || $input.first().json.text
  || '';

let cleaned = raw.trim();
cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '');

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  // Malformed JSON from Intent Parser itself -> force safe fallback
  // (do NOT throw here; route to needs_analysis so downstream AI Analyzer
  // can still attempt to handle the raw user message with full context)
  const original = $('Normalize Input').first().json;
  return [{
    json: {
      route: 'needs_analysis',
      confidence: 'low',
      target_file: null,
      action_type: 'read_only',
      clarified_intent: original.user_message,
      original_message: original.user_message,
      parse_error: true,
      parse_error_detail: err.message
    }
  }];
}

// Defensive defaults in case model omits a field
const original = $('Normalize Input').first().json;

return [{
  json: {
    route: parsed.route === 'direct_hit' ? 'direct_hit' : 'needs_analysis',
    confidence: parsed.confidence || 'low',
    target_file: parsed.target_file || null,
    action_type: parsed.action_type || 'update',
    clarified_intent: parsed.clarified_intent || original.user_message,
    original_message: original.user_message,
    repo_owner: original.repo_owner,
    repo_name: original.repo_name,
    branch: original.branch,
    chat_id: original.chat_id,
    parse_error: false
  }
}];

// Needs Analysis path
// Target file unknown or confidence too low for direct execution.
// Shapes payload for the full repo tree fetch -> AI Analyzer pipeline (Stage 2/3).

const input = $input.first().json;

return [{
  json: {
    ...input,
    resolution_path: 'needs_analysis',
    fetch_mode: 'full_tree',
    files_to_fetch: [],
    skip_analyzer: false
  }
}];

// Direct Hit Resolver
// Target file & action are already clear from Intent Parser.
// This node just shapes the payload for the single-file fetch path,
// SKIPPING the full repo tree fetch + AI Analyzer stage entirely.

const input = $input.first().json;

return [{
  json: {
    ...input,
    resolution_path: 'direct_hit',
    fetch_mode: 'single_file',
    files_to_fetch: [input.target_file],
    skip_analyzer: true
  }
}];

// ============================================================
// SELF-HEALING LAYER 1 — Technical/Infrastructure Diagnosis
// Pure deterministic logic. No AI call.
// Handles both Contents API (single file) and Git Trees API (full tree) responses.
// ============================================================

const item = $input.first().json;
const upstream = $('IF Direct Hit Path?').first().json;

// n8n httpRequest with fullResponse:true + neverError:true wraps the real
// response under .body and always gives us .statusCode regardless of success/fail.
const statusCode = item.statusCode || null;
const body = item.body || {};
const headers = item.headers || {};

const retryCount = upstream.retry_count || 0;
const MAX_RETRY_RATELIMIT = 3;
const MAX_RETRY_PATH = 2;
const MAX_RETRY_GENERIC = 1;

let diagnosis = {
  ...upstream,
  retry_count: retryCount,
  status_code: statusCode,
  fetch_mode: upstream.fetch_mode
};

// --- SUCCESS PATH ---
if (statusCode >= 200 && statusCode < 300) {

  if (upstream.fetch_mode === 'single_file') {
    // Contents API success
    if (!body.content || body.encoding !== 'base64') {
      diagnosis.action = retryCount < MAX_RETRY_GENERIC ? 'retry_no_wait' : 'stop_alert';
      diagnosis.reason = 'Response sukses tapi field content/encoding tidak sesuai ekspektasi Contents API';
      diagnosis.retry_count = retryCount + 1;
      diagnosis.wait_seconds = 0;
      return [{ json: diagnosis }];
    }

    let decoded;
    try {
      decoded = Buffer.from(body.content, 'base64').toString('utf-8');
    } catch (err) {
      diagnosis.action = retryCount < MAX_RETRY_GENERIC ? 'retry_no_wait' : 'stop_alert';
      diagnosis.reason = 'Base64 decode gagal: ' + err.message;
      diagnosis.retry_count = retryCount + 1;
      diagnosis.wait_seconds = 0;
      return [{ json: diagnosis }];
    }

    diagnosis.action = 'success';
    diagnosis.file_content = decoded;
    diagnosis.file_sha = body.sha;
    diagnosis.file_path = body.path;
    diagnosis.file_size = body.size;
    return [{ json: diagnosis }];
  }

  if (upstream.fetch_mode === 'full_tree') {
    // Git Trees API success
    if (!Array.isArray(body.tree)) {
      diagnosis.action = retryCount < MAX_RETRY_GENERIC ? 'retry_no_wait' : 'stop_alert';
      diagnosis.reason = 'Response sukses tapi field tree[] tidak ditemukan';
      diagnosis.retry_count = retryCount + 1;
      diagnosis.wait_seconds = 0;
      return [{ json: diagnosis }];
    }

    diagnosis.action = 'success';
    diagnosis.tree = body.tree.map(t => ({ path: t.path, type: t.type, size: t.size || null }));
    diagnosis.tree_truncated = body.truncated === true;

    if (diagnosis.tree_truncated) {
      // Not a hard error, but downstream (AI Analyzer) must know the tree
      // is incomplete so it doesn't assume full repo visibility.
      diagnosis.warning = 'GitHub memotong hasil tree (truncated=true). Repo terlalu besar untuk 1 call recursive. AI Analyzer harus fetch per-folder untuk area yang relevan.';
    }
    return [{ json: diagnosis }];
  }
}

// --- ERROR PATH ---
const errorMessage = (body.message || '').toLowerCase();
const rateLimitRemaining = headers['x-ratelimit-remaining'];

if (statusCode === 401 || errorMessage.includes('bad credentials')) {
  diagnosis.action = 'stop_alert';
  diagnosis.reason = 'GitHub PAT invalid atau expired. Cek ulang token di credential.';

} else if (statusCode === 403 && (rateLimitRemaining === '0' || errorMessage.includes('rate limit'))) {
  if (retryCount >= MAX_RETRY_RATELIMIT) {
    diagnosis.action = 'stop_alert';
    diagnosis.reason = `Rate limit GitHub masih kena setelah ${retryCount}x retry`;
  } else {
    diagnosis.action = 'retry_with_wait';
    diagnosis.reason = 'GitHub API rate limit tercapai';
    diagnosis.wait_seconds = 5 * Math.pow(3, retryCount); // 5s, 15s, 45s
    diagnosis.retry_count = retryCount + 1;
  }

} else if (statusCode === 403) {
  diagnosis.action = 'stop_alert';
  diagnosis.reason = 'GitHub menolak akses (403) bukan karena rate limit — kemungkinan PAT tidak punya permission ke repo ini';

} else if (statusCode === 404) {
  if (retryCount >= MAX_RETRY_PATH) {
    diagnosis.action = 'stop_alert';
    diagnosis.reason = `Path/branch tidak ditemukan setelah ${retryCount}x percobaan normalisasi: ${upstream.target_file || upstream.branch}`;
  } else {
    diagnosis.action = 'path_normalize_retry';
    diagnosis.reason = 'Path file atau nama branch kemungkinan salah / case-sensitivity issue';
    diagnosis.wait_seconds = 0;
    diagnosis.retry_count = retryCount + 1;
    diagnosis.normalized_target_file = (upstream.target_file || '').trim().replace(/^\/+/, '');
  }

} else if (statusCode === 409) {
  diagnosis.action = 'stop_alert';
  diagnosis.reason = 'Conflict (409) — kemungkinan repo kosong atau branch belum punya commit sama sekali';

} else if (statusCode === null) {
  diagnosis.action = retryCount < MAX_RETRY_GENERIC ? 'retry_no_wait' : 'stop_alert';
  diagnosis.reason = 'Tidak ada response sama sekali (kemungkinan network timeout)';
  diagnosis.retry_count = retryCount + 1;
  diagnosis.wait_seconds = 0;

} else {
  // Unrecognized error — do not blindly auto-retry
  diagnosis.action = 'stop_alert';
  diagnosis.reason = `Error tidak dikenali (status ${statusCode}): ${errorMessage || 'unknown'}`;
}

return [{ json: diagnosis }];

// Apply path normalization (if any) before looping back to fetch.
// Also carries forward the incremented retry_count so the loop terminates.

const item = $input.first().json;

const output = { ...item };

if (item.normalized_target_file) {
  output.target_file = item.normalized_target_file;
}

return [{ json: output }];

