// Stage 2 successful output contract.
// This is what gets returned to whatever called this sub-workflow
// (either back to Stage 1 orchestrator, or directly to Stage 3 AI Analyzer
// depending on how the parent workflow wires Execute Workflow nodes).

const item = $input.first().json;

return [{
  json: {
    resolution_path: item.resolution_path,
    fetch_mode: item.fetch_mode,
    repo_owner: item.repo_owner,
    repo_name: item.repo_name,
    branch: item.branch,
    chat_id: item.chat_id,
    clarified_intent: item.clarified_intent,
    action_type: item.action_type,
    skip_analyzer: item.skip_analyzer,
    // single_file mode fields
    file_content: item.file_content || null,
    file_path: item.file_path || null,
    file_sha: item.file_sha || null,
    // full_tree mode fields
    tree: item.tree || null,
    tree_truncated: item.tree_truncated || false,
    tree_warning: item.warning || null
  }
}];

// Init Analyzer Loop
// Sets up the loop state used to bound how many rounds the AI Analyzer
// can request additional files before being forced to conclude.

const input = $input.first().json;

return [{
  json: {
    ...input,
    analysis_round: 1,
    max_rounds: 3,
    force_conclude: false,
    fetched_files: {}, // { "path/to/file.ts": "...content..." }
    fetch_failures: [] // paths that failed to fetch, so AI doesn't re-request them blindly
  }
}];

// Build the prompt context for this round.
// Compresses tree + already-fetched file contents into a single string
// so the OpenAI node's user message stays simple.

const input = $input.first().json;

const treeSummary = Array.isArray(input.tree)
  ? input.tree.filter(t => t.type === 'blob').map(t => t.path).join('\n')
  : '(tidak ada tree, mode single_file)';

const fetchedSummary = Object.entries(input.fetched_files || {})
  .map(([path, content]) => `--- FILE: ${path} ---\n${content}\n--- END FILE ---`)
  .join('\n\n') || '(belum ada file yang di-fetch)';

const failuresSummary = (input.fetch_failures || []).length > 0
  ? `File yang GAGAL di-fetch sebelumnya (jangan diminta lagi): ${input.fetch_failures.join(', ')}`
  : '';

const truncatedNote = input.tree_truncated
  ? '\nPERHATIAN: tree di atas TERPOTONG (repo terlalu besar). Jika file relevan tidak terlihat di daftar, sebutkan di reasoning bahwa kamu perlu eksplorasi folder tertentu.'
  : '';

return [{
  json: {
    ...input,
    prompt_tree_summary: treeSummary,
    prompt_fetched_summary: fetchedSummary,
    prompt_failures_summary: failuresSummary,
    prompt_truncated_note: truncatedNote
  }
}];

