// Parse AI Analyzer's JSON output safely.

const raw = $input.first().json.message?.content
  || $input.first().json.content
  || $input.first().json.text
  || '';

let cleaned = raw.trim();
cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '');

const loopState = $('Build Round Context').first().json;

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  // Malformed JSON from Analyzer -> force conclude with whatever we have,
  // rather than crashing the whole pipeline.
  return [{
    json: {
      ...loopState,
      status: 'ready',
      files_needed: [],
      reasoning: 'Analyzer output tidak valid JSON, forced ready dengan data yang tersedia.',
      analysis: {
        files_to_modify: [],
        context_notes: 'PARSE ERROR pada AI Analyzer round ' + loopState.analysis_round + ': ' + err.message
      },
      analyzer_parse_error: true
    }
  }];
}

return [{
  json: {
    ...loopState,
    status: parsed.status === 'ready' ? 'ready' : 'need_more_files',
    files_needed: Array.isArray(parsed.files_needed) ? parsed.files_needed : [],
    reasoning: parsed.reasoning || '',
    analysis: parsed.analysis || null,
    analyzer_parse_error: false
  }
}];

// Format Stage 3 successful output contract.
// This goes to Stage 4 (Code Generator).

const item = $input.first().json;

return [{
  json: {
    repo_owner: item.repo_owner,
    repo_name: item.repo_name,
    branch: item.branch,
    chat_id: item.chat_id,
    clarified_intent: item.clarified_intent,
    action_type: item.action_type,
    analysis: item.analysis,
    fetched_files: item.fetched_files,
    rounds_used: item.analysis_round,
    analyzer_forced_conclude: item.force_conclude === true,
    analyzer_parse_error: item.analyzer_parse_error === true
  }
}];

// Mark force_conclude so the NEXT Analyzer call is told (in the system
// prompt) that this is the final round and it must return status:ready.
// We still loop back through one more AI call rather than fabricating
// the analysis ourselves — only the AI has the context to summarize
// what's known so far.

const item = $input.first().json;

return [{
  json: {
    ...item,
    force_conclude: true
  }
}];

// Split files_needed into separate items so Execute Workflow can
// (depending on n8n's batch/loop execution mode) fetch each one,
// while preserving the shared loop state for re-merging afterward.

const item = $input.first().json;
const filesNeeded = item.files_needed || [];

return filesNeeded.map(path => ({
  json: {
    repo_owner: item.repo_owner,
    repo_name: item.repo_name,
    branch: item.branch,
    chat_id: item.chat_id,
    clarified_intent: item.clarified_intent,
    action_type: item.action_type,
    target_file: path,
    skip_analyzer: true,
    fetch_mode: 'single_file',
    resolution_path: 'analyzer_requested',
    retry_count: 0,
    _loop_state: item // carry full loop state through, unpacked after fetch
  }
}));

// Merge all fetched files (success or failure) back into one item,
// reconstructing the shared loop state, then increment the round counter.
// Runs once, AFTER the file-fetch loop (Loop Over Items) has finished
// iterating every requested file via Fetch File In Loop -> Diagnose Fetch In Loop.

const items = $input.all();
const requestItems = $('Prepare File Requests').all();

// loop_state was identical across all items in this round; take from the first request
const loopState = requestItems[0]?.json._loop_state || {};

const fetchedFiles = { ...(loopState.fetched_files || {}) };
const fetchFailures = [ ...(loopState.fetch_failures || []) ];

items.forEach((item) => {
  const result = item.json;
  const requestedPath = result.target_file;

  if (result.loop_action === 'success' && result.file_content && requestedPath) {
    fetchedFiles[requestedPath] = result.file_content;
  } else if (requestedPath) {
    fetchFailures.push(requestedPath);
  }
});

return [{
  json: {
    ...loopState,
    fetched_files: fetchedFiles,
    fetch_failures: fetchFailures,
    analysis_round: loopState.analysis_round + 1
  }
}];

// Init Generator/Validator loop state
const input = $input.first().json;

return [{
  json: {
    ...input,
    repair_attempts: 0,
    max_repair_attempts: 2,
    last_validation_errors: []
  }
}];

const input = $input.first().json;

// =============================
// NORMALIZE FILE INPUT
// =============================
let files = {};

// Case 1: batch format
if (input.fetched_files && typeof input.fetched_files === 'object') {
  files = input.fetched_files;
}

// Case 2: single file format
else if (input.file_path && input.file_content) {
  files[input.file_path] = input.file_content;
}

// =============================
// BUILD FILE CONTEXT
// =============================
const filesContext = Object.keys(files).length > 0
  ? Object.entries(files)
      .map(([path, content]) =>
`--- FILE: ${path} ---
${content}
--- END FILE ---`
      )
      .join('\n\n')
  : '(tidak ada file fetched, gunakan analysis.files_to_modify sebagai panduan)';

// =============================
// FILES TO MODIFY CONTEXT
// =============================
const filesToModify = (input.analysis?.files_to_modify || [])
  .map(f =>
`- ${f.path}: ${f.change_summary} (${f.relevant_lines_or_section})`
  )
  .join('\n') || '(tidak ada instruksi file modify)';

// =============================
// REPAIR NOTE
// =============================
const repairNote = input.repair_attempts > 0
  ? `
INI ADALAH PERCOBAAN PERBAIKAN ke-${input.repair_attempts}.
Output sebelumnya GAGAL validasi dengan error berikut:

${JSON.stringify(input.last_validation_errors, null, 2)}
`
  : '';

// =============================
// OUTPUT
// =============================
return [{
  json: {
    ...input,
    normalized_files: files,
    prompt_files_context: filesContext,
    prompt_files_to_modify: filesToModify,
    prompt_repair_note: repairNote
  }
}];

