// Parse Code Generator's JSON output safely.

const raw = $input.first().json.message?.content
  || $input.first().json.content
  || $input.first().json.text
  || '';

let cleaned = raw.trim();
cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '');

const loopState = $('Build Generator Context').first().json;

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  return [{
    json: {
      ...loopState,
      generator_output: { files: [] },
      generator_parse_error: true,
      generator_parse_error_detail: err.message
    }
  }];
}

return [{
  json: {
    ...loopState,
    generator_output: parsed,
    generator_parse_error: false
  }
}];

// ============================================================
// VALIDATOR (Self-Healing Layer 2 - deterministic gate)
// Pure JS, no AI call. Checks:
//   1. Generator JSON structure itself valid
//   2. Every edit's "search" text exists EXACTLY ONCE in the target file
//   3. After virtually applying all edits, basic syntax sanity (balanced
//      brackets/braces/parens) holds for the patched result
// Produces patched_files{} ready for commit ONLY if fully valid.
// ============================================================

const state = $input.first().json;
const errors = [];
const patchedFiles = {};

if (!state.generator_output) {
  return [{
    json: {
      valid: false,
      validation_errors: [
        {
          type: "missing_generator_output",
          detail: "generator_output not found"
        }
      ]
    }
  }];
}

if (state.generator_parse_error) {
  errors.push({ type: 'json_parse_error', detail: state.generator_parse_error_detail });
}

const genOutput = state.generator_output || {};
const files = Array.isArray(genOutput.files) ? genOutput.files : [];

if (files.length === 0 && !state.generator_parse_error) {
  errors.push({ type: 'empty_output', detail: 'Code Generator tidak menghasilkan file apapun untuk diubah' });
}

function checkBalanced(text) {
  const pairs = { '(': ')', '{': '}', '[': ']' };
  const closers = new Set(Object.values(pairs));
  const stack = [];
  let inString = null; // tracks ' " ` while scanning, to skip brackets inside strings
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    const prev = text[i - 1];

    if (inString) {
      if (ch === inString && prev !== '\\') inString = null;
      continue;
    }
    if (ch === '"' || ch === "'" || ch === '`') { inString = ch; continue; }

    if (pairs[ch]) stack.push(pairs[ch]);
    else if (closers.has(ch)) {
      if (stack.pop() !== ch) return false;
    }
  }
  return stack.length === 0;
}

for (const file of files) {
  if (!file.path || !Array.isArray(file.edits) || file.edits.length === 0) {
    errors.push({ type: 'malformed_file_entry', detail: `File entry tidak lengkap: ${JSON.stringify(file).slice(0, 200)}` });
    continue;
  }

  const originalContent = (state.fetched_files || {})[file.path];
  if (typeof originalContent !== 'string') {
    errors.push({ type: 'unknown_file', path: file.path, detail: 'File tidak ada di fetched_files, tidak bisa di-patch' });
    continue;
  }

  let working = originalContent;
  let fileHasError = false;

  for (const edit of file.edits) {
    if (typeof edit.search !== 'string' || typeof edit.replace !== 'string' || edit.search.length === 0) {
      errors.push({ type: 'malformed_edit', path: file.path, detail: 'edit.search/replace tidak valid atau kosong' });
      fileHasError = true;
      continue;
    }

    const occurrences = working.split(edit.search).length - 1;
    if (occurrences === 0) {
      errors.push({ type: 'search_not_found', path: file.path, detail: `Teks search tidak ditemukan persis di file: "${edit.search.slice(0, 80)}..."` });
      fileHasError = true;
      continue;
    }
    if (occurrences > 1) {
      errors.push({ type: 'search_ambiguous', path: file.path, detail: `Teks search match ${occurrences}x (harus unik 1x): "${edit.search.slice(0, 80)}..."` });
      fileHasError = true;
      continue;
    }

    working = working.replace(edit.search, edit.replace);
  }

  if (!fileHasError) {
    if (!checkBalanced(working)) {
      errors.push({ type: 'unbalanced_brackets', path: file.path, detail: 'Hasil patch memiliki kurung/brace/bracket tidak seimbang' });
      fileHasError = true;
    }
  }

  if (!fileHasError) {
    patchedFiles[file.path] = {
      content: working,
      sha: (state.fetched_file_shas || {})[file.path] || null,
      commit_message: file.commit_message || `CTO Agent: update ${file.path}`
    };
  }
}

const valid = errors.length === 0 && Object.keys(patchedFiles).length > 0;

return [{
  json: {
    ...state,
    valid,
    validation_errors: errors,
    patched_files: patchedFiles
  }
}];

// Prepare state for the Repair Engine call: carry validation_errors
// forward as last_validation_errors, increment attempt counter.

const state = $input.first().json;

return [{
  json: {
    ...state,
    last_validation_errors: state.validation_errors,
    repair_attempts: (state.repair_attempts || 0) + 1
  }
}];

