// ============================================================
// SELF-HEALING for files requested by AI Analyzer inside the loop.
// Adapted from "Diagnose Error (Self-Healing L1)" but scoped so that
// a single failed file NEVER stops the whole pipeline (no stop_alert
// here) — it only ever resolves to 'success' or 'mark_failed', so the
// loop can move on to the next file regardless.
//
// IMPORTANT: "Fetch File In Loop" (HTTP Request node) REPLACES $json
// with the raw response ({ body, statusCode, headers }) — it does NOT
// carry forward target_file / _loop_state / loop_retry_count.
// We read those from "Set Fetch Context" instead of "Loop Over Items",
// because Set Fetch Context re-runs on EVERY attempt (initial + every
// retry), while Loop Over Items only runs once per file and would always
// report retry_count = 0 on retries -> infinite retry risk.
// ============================================================

const httpResult = $input.first().json;
const upstream = $('Set Fetch Context').first().json;

const statusCode = httpResult.statusCode || null;
const body = httpResult.body || {};
const headers = httpResult.headers || {};

const retryCount = upstream.loop_retry_count || 0;
const MAX_RETRY_RATELIMIT = 3;
const MAX_RETRY_GENERIC = 1;

let diagnosis = {
  ...upstream,
  loop_retry_count: retryCount
};

// --- SUCCESS PATH ---
if (statusCode >= 200 && statusCode < 300) {
  if (!body.content || body.encoding !== 'base64') {
    diagnosis.loop_action = 'mark_failed';
    diagnosis.loop_fail_reason = 'Response sukses tapi field content/encoding tidak sesuai ekspektasi Contents API';
    return [{ json: diagnosis }];
  }

  let decoded;
  try {
    decoded = Buffer.from(body.content, 'base64').toString('utf-8');
  } catch (err) {
    diagnosis.loop_action = 'mark_failed';
    diagnosis.loop_fail_reason = 'Base64 decode gagal: ' + err.message;
    return [{ json: diagnosis }];
  }

  diagnosis.loop_action = 'success';
  diagnosis.file_content = decoded;
  diagnosis.file_sha = body.sha;
  diagnosis.file_path = body.path;
  return [{ json: diagnosis }];
}

// --- ERROR PATH (bounded retry, never stop_alert) ---
const errorMessage = (body.message || '').toLowerCase();
const rateLimitRemaining = headers['x-ratelimit-remaining'];

if (statusCode === 403 && (rateLimitRemaining === '0' || errorMessage.includes('rate limit'))) {
  if (retryCount >= MAX_RETRY_RATELIMIT) {
    diagnosis.loop_action = 'mark_failed';
    diagnosis.loop_fail_reason = `Rate limit GitHub masih kena setelah ${retryCount}x retry`;
  } else {
    diagnosis.loop_action = 'retry_with_wait';
    diagnosis.loop_wait_seconds = 5 * Math.pow(3, retryCount); // 5s, 15s, 45s
    diagnosis.loop_retry_count = retryCount + 1;
  }
} else if (statusCode === 404) {
  if (retryCount >= MAX_RETRY_GENERIC) {
    diagnosis.loop_action = 'mark_failed';
    diagnosis.loop_fail_reason = `404 Not Found untuk path: ${upstream.target_file}`;
  } else {
    diagnosis.loop_action = 'retry_no_wait';
    diagnosis.loop_retry_count = retryCount + 1;
  }
} else if (statusCode === null) {
  if (retryCount >= MAX_RETRY_GENERIC) {
    diagnosis.loop_action = 'mark_failed';
    diagnosis.loop_fail_reason = 'Tidak ada response (kemungkinan network timeout)';
  } else {
    diagnosis.loop_action = 'retry_no_wait';
    diagnosis.loop_retry_count = retryCount + 1;
  }
} else {
  diagnosis.loop_action = 'mark_failed';
  diagnosis.loop_fail_reason = `Error tidak dikenali (status ${statusCode}): ${errorMessage || 'unknown'}`;
}

return [{ json: diagnosis }];

// Passthrough node — exists purely so Diagnose Fetch In Loop can reliably
// reference $('Set Fetch Context').first().json to get the CURRENT
// target_file / loop_retry_count, regardless of whether this run came
// from the initial loop iteration or a retry cycle. This avoids relying
// on $('Loop Over Items'), which never re-runs during retries and would
// always report retry_count = 0 (infinite-retry risk).

const item = $input.first().json;
return [{ json: { ...item } }];
